#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;

    // Use difference array technique: we only need two passes.
    // Since n can be up to 1e7, we allocate a vector of int64_t.
    vector<long long> diff(n + 2, 0);

    for (int i = 0; i < m; i++) {
        int a, b;
        long long k;
        cin >> a >> b >> k;
        diff[a] += k;
        diff[b + 1] -= k;
    }

    long long cur = 0;
    long long ans = 0;
    for (int i = 1; i <= n; i++) {
        cur += diff[i];
        if (cur > ans) ans = cur;
    }

    cout << ans << '\n';

    return 0;
}
